object Solution { def errors_per_hour(lines: Seq[String]): Map[String, Int] = { val counts = scala.collection.mutable.Map[String, Int]().withDefaultValue(0); for (line <- lines) { val parts = line.split(" ", 3); if (parts.length >= 2 && parts(1) == "ERROR" && parts(0).length >= 13 && parts(0).charAt(10) == 'T') counts(parts(0).substring(0, 13)) += 1 }; counts.toMap } }
